Here’s a clean reimplementation from scratch of what the obfuscated code is doing.

It implements an **A\*** pathfinding search on a randomly generated grid with:

- grid size: `20 x 15`
- blocked cells generated randomly using `clearanceRatio`
- 8-direction movement
- orthogonal move cost: `traversalCost`
- diagonal move cost: `adjacentCost`
- heuristic: either `"manhattan"` or Euclidean
- a search iteration cap via `minIterations`

```javascript
const gridWidth = 20;
const gridHeight = 15;

const config = {
  penalty: "manhattan",   // or anything else to use Euclidean
  adjacentCost: 1.414,    // diagonal movement cost
  traversalCost: 1,       // orthogonal movement cost
  minIterations: 1000,    // iteration cap
  clearanceRatio: 0.25    // chance a cell is blocked
};

// Build random grid: 0 = walkable, 1 = blocked
const grid = [];
for (let y = 0; y < gridHeight; y++) {
  grid[y] = [];
  for (let x = 0; x < gridWidth; x++) {
    grid[y][x] = Math.random() < config.clearanceRatio ? 1 : 0;
  }
}

const start = { x: 0, y: 0 };
const goal = { x: gridWidth - 1, y: gridHeight - 1 };

// Ensure start and goal are always walkable
grid[start.y][start.x] = 0;
grid[goal.y][goal.x] = 0;

function heuristic(a, b) {
  const dx = Math.abs(a.x - b.x);
  const dy = Math.abs(a.y - b.y);

  if (config.penalty === "manhattan") {
    return dx + dy;
  }

  return Math.sqrt(dx * dx + dy * dy);
}

function getNeighbors(node) {
  const directions = [
    { dx: 0,  dy: -1, cost: config.traversalCost },
    { dx: 0,  dy: 1,  cost: config.traversalCost },
    { dx: -1, dy: 0,  cost: config.traversalCost },
    { dx: 1,  dy: 0,  cost: config.traversalCost },
    { dx: -1, dy: -1, cost: config.adjacentCost },
    { dx: 1,  dy: -1, cost: config.adjacentCost },
    { dx: -1, dy: 1,  cost: config.adjacentCost },
    { dx: 1,  dy: 1,  cost: config.adjacentCost }
  ];

  const neighbors = [];

  for (const dir of directions) {
    const x = node.x + dir.dx;
    const y = node.y + dir.dy;

    const inBounds =
      x >= 0 &&
      x < gridWidth &&
      y >= 0 &&
      y < gridHeight;

    if (!inBounds) continue;
    if (grid[y][x] !== 0) continue;

    neighbors.push({
      x,
      y,
      moveCost: dir.cost
    });
  }

  return neighbors;
}

function keyOf(node) {
  return `${node.x},${node.y}`;
}

function parseKey(key) {
  const [x, y] = key.split(",").map(Number);
  return { x, y };
}

function findRoute(startNode, goalNode) {
  const openSet = {};
  const closedSet = {};
  const cameFrom = {};
  const gScore = {};
  const fScore = {};

  const startKey = keyOf(startNode);

  openSet[startKey] = startNode;
  gScore[startKey] = 0;
  fScore[startKey] = heuristic(startNode, goalNode);

  let iterations = 0;

  while (Object.keys(openSet).length > 0 && iterations < config.minIterations) {
    iterations++;

    // Find node in open set with lowest fScore
    let currentKey = null;
    let bestScore = Infinity;

    for (const key in openSet) {
      if (fScore[key] < bestScore) {
        bestScore = fScore[key];
        currentKey = key;
      }
    }

    const current = openSet[currentKey];

    // Goal reached
    if (current.x === goalNode.x && current.y === goalNode.y) {
      const path = [current];
      let walkKey = currentKey;

      while (cameFrom[walkKey]) {
        walkKey = cameFrom[walkKey];
        path.push(openSet[walkKey] || closedSet[walkKey] || parseKey(walkKey));
      }

      return {
        path,
        cost: gScore[currentKey],
        iterations
      };
    }

    delete openSet[currentKey];
    closedSet[currentKey] = current;

    for (const neighbor of getNeighbors(current)) {
      const neighborKey = keyOf(neighbor);

      if (closedSet[neighborKey]) {
        continue;
      }

      const tentativeG = gScore[currentKey] + neighbor.moveCost;

      if (gScore[neighborKey] === undefined || tentativeG < gScore[neighborKey]) {
        cameFrom[neighborKey] = currentKey;
        gScore[neighborKey] = tentativeG;
        fScore[neighborKey] = tentativeG + heuristic(neighbor, goalNode);
        openSet[neighborKey] = neighbor;
      }
    }
  }

  return {
    path: [],
    cost: Infinity,
    iterations
  };
}

const result = findRoute(start, goal);

console.log(
  "Path length:",
  result.path.length,
  "Cost:",
  result.cost,
  "Iterations:",
  result.iterations
);
```

### Notes on behavior
This preserves the actual behavior of the original code, including a few quirks:

- The returned `path` is built **from goal back to start** rather than start to goal.
- It uses plain objects for the open/closed sets instead of a priority queue.
- The loop stops when iterations reach `config.minIterations`, even though that name sounds like it should be a minimum rather than a maximum.
- Diagonal moves are allowed freely; there is **no corner-cutting prevention**.

